/**
 * Create User Page
 *
 * Admin page for creating new users.
 * Features:
 * - Email and name input
 * - Optional welcome email
 * - Displays temporary password after creation
 */

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAdmin } from '../../hooks/useAdmin';
import ErrorMessage from '../../components/ErrorMessage';
import LoadingSpinner from '../../components/LoadingSpinner';
import AdminPageHeader from '../../components/AdminPageHeader';

const CreateUserPage: React.FC = () => {
  const navigate = useNavigate();
  const admin = useAdmin();
  const [email, setEmail] = useState('');
  const [name, setName] = useState('');
  const [sendWelcomeEmail, setSendWelcomeEmail] = useState(true);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [createdUser, setCreatedUser] = useState<{
    email: string;
    message: string;
    passwordViewLink?: string;
  } | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      const result = await admin.createUser({
        email,
        name: name || undefined,
        sendWelcomeEmail,
      });

      // Show success message
      setCreatedUser({
        email: result.user.email,
        message: result.message,
        passwordViewLink: result.passwordViewLink,
      });

      // Clear form
      setEmail('');
      setName('');
      setSendWelcomeEmail(true);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to create user');
    } finally {
      setLoading(false);
    }
  };

  const handleClose = () => {
    setCreatedUser(null);
    navigate('/admin/users');
  };

  // Success Modal
  if (createdUser) {
    return (
      <div className="container mx-auto px-4 py-8 max-w-2xl">
        <div className="bg-white shadow-md rounded p-6">
          <div className="text-center mb-6">
            <div className="text-green-500 text-6xl mb-4">✓</div>
            <h2 className="text-2xl font-bold text-gray-900">User Created Successfully</h2>
          </div>

          <div className="bg-gray-50 rounded p-4 mb-6">
            <p className="text-sm text-gray-600 mb-2">Email:</p>
            <p className="text-lg font-semibold text-gray-900">{createdUser.email}</p>
          </div>

          <div className="bg-blue-50 border-l-4 border-blue-400 p-4 mb-6">
            <p className="text-sm text-blue-700">
              <strong>✓ {createdUser.message}</strong>
            </p>
            {createdUser.passwordViewLink ? (
              <>
                <p className="text-xs text-blue-600 mt-2">
                  Please share this one-time password link with the user:
                </p>
                <div className="mt-3 bg-white rounded p-3 border border-blue-200">
                  <code className="text-xs text-gray-700 break-all">
                    {createdUser.passwordViewLink}
                  </code>
                </div>
                <button
                  onClick={() => {
                    navigator.clipboard.writeText(createdUser.passwordViewLink!);
                    alert('Password link copied to clipboard!');
                  }}
                  className="mt-3 text-xs text-blue-600 hover:text-blue-800 underline"
                >
                  📋 Copy link to clipboard
                </button>
              </>
            ) : (
              <p className="text-xs text-blue-600 mt-2">
                The user will receive a secure one-time link to view their temporary password. The
                link expires in 24 hours.
              </p>
            )}
          </div>

          <div className="flex gap-3">
            <button
              onClick={handleClose}
              className="flex-1 bg-blue-600 text-white px-6 py-3 rounded hover:bg-blue-700 font-medium"
            >
              Back to User List
            </button>
            <button
              onClick={() => {
                setCreatedUser(null);
                setEmail('');
                setName('');
              }}
              className="flex-1 bg-gray-600 text-white px-6 py-3 rounded hover:bg-gray-700 font-medium"
            >
              Create Another User
            </button>
          </div>
        </div>
      </div>
    );
  }

  // Create User Form
  return (
    <div className="container mx-auto px-4 py-8 max-w-2xl">
      <AdminPageHeader title="Create New User" />

      <div className="bg-white shadow-md rounded p-6">
        {error && <ErrorMessage message={error} />}

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label htmlFor="email" className="block text-sm font-medium text-gray-700 mb-2">
              Email Address <span className="text-red-500">*</span>
            </label>
            <input
              id="email"
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
              disabled={loading}
              className="w-full px-4 py-2 border border-gray-300 rounded focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:bg-gray-100"
              placeholder="user@example.com"
            />
            <p className="text-xs text-gray-500 mt-1">
              User will receive a welcome email with login instructions
            </p>
          </div>

          <div>
            <label htmlFor="name" className="block text-sm font-medium text-gray-700 mb-2">
              Full Name <span className="text-gray-400">(Optional)</span>
            </label>
            <input
              id="name"
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              disabled={loading}
              className="w-full px-4 py-2 border border-gray-300 rounded focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:bg-gray-100"
              placeholder="John Doe"
            />
          </div>

          <div className="flex items-center">
            <input
              id="sendWelcomeEmail"
              type="checkbox"
              checked={sendWelcomeEmail}
              onChange={(e) => setSendWelcomeEmail(e.target.checked)}
              disabled={loading}
              className="h-4 w-4 text-blue-600 focus:ring-blue-500 border-gray-300 rounded"
            />
            <label htmlFor="sendWelcomeEmail" className="ml-2 block text-sm text-gray-700">
              Send welcome email with login instructions
            </label>
          </div>

          <div className="bg-blue-50 border-l-4 border-blue-400 p-4">
            <p className="text-sm text-blue-700">
              <strong>Note:</strong> A temporary password will be generated for this user. They will
              be required to change it on first login.
            </p>
          </div>

          <div className="flex gap-3">
            <button
              type="button"
              onClick={() => navigate('/admin/users')}
              disabled={loading}
              className="flex-1 bg-gray-300 text-gray-700 px-6 py-3 rounded hover:bg-gray-400 font-medium disabled:opacity-50"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={loading || !email}
              className="flex-1 bg-blue-600 text-white px-6 py-3 rounded hover:bg-blue-700 font-medium disabled:opacity-50 flex items-center justify-center"
            >
              {loading ? <LoadingSpinner size="small" /> : 'Create User'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default CreateUserPage;
